export const findBrandByCamping = (campingLabel) => {
  if (!campingLabel) return BRANDS[0];
  for (const brand of BRANDS) {
    const list = CAMPINGS_BY_BRAND[brand] || [];
    if (list.some((item) => item.label === campingLabel)) return brand;
  }
  return BRANDS[0];
};
